arguments.command:
# Try llvm-symbolizer for the unresolved addresses, and also try with the stripped binary
DEBUGFILE="/tmp/libmonosgen-debug2.so"

# Try with llvm-symbolizer
for addr in 0x2f4b20 0x2f4c84; do
  echo "=== $addr ==="
  llvm-symbolizer --obj="$DEBUGFILE" "$addr" 2>&1
  echo
done

echo "=== Trying nm to find nearest symbols ==="
aarch64-linux-gnu-nm -C "$DEBUGFILE" 2>/dev/null | sort | awk -v a1="2f4b20" -v a2="2f4c84" '
  { addr=$1; sym=$3 }
  addr <= a1 { before1=addr" "$sym }
  addr <= a2 { before2=addr" "$sym }
  addr > a1 && !found1 { print "0x2f4b20 -> " before1 " ... next: " addr " " sym; found1=1 }
  addr > a2 && !found2 { print "0x2f4c84 -> " before2 " ... next: " addr " " sym; found2=1 }
'

